document.addEventListener("DOMContentLoaded",function(){const section=document.querySelector(".company-management");const track=document.getElementById("cmSliderTrack");const pagination=document.getElementById("cmPagination");const viewport=document.querySelector(".cm-slider-viewport");let originalItems=Array.from(track.querySelectorAll(".cm-item"));const realCount=originalItems.length;originalItems.forEach(function(item,index){item.dataset.realIndex=index});const beforeClones=originalItems.map(function(item){const clone=item.cloneNode(true);clone.classList.remove("active");clone.dataset.clone="before";return clone});const afterClones=originalItems.map(function(item){const clone=item.cloneNode(true);clone.classList.remove("active");clone.dataset.clone="after";return clone});beforeClones.forEach(function(clone){track.insertBefore(clone,originalItems[0])});afterClones.forEach(function(clone){track.appendChild(clone)});let items=Array.from(track.querySelectorAll(".cm-item"));let currentRealIndex=0;let currentDomIndex=realCount;let isAnimating=false;pagination.innerHTML="";for(let i=0;i<realCount;i++){const btn=document.createElement("button");btn.className="cm-page";btn.textContent=i+1;btn.dataset.index=i;if(i===0){btn.classList.add("active")}btn.addEventListener("click",function(){goToRealIndex(i)});pagination.appendChild(btn)}const pages=Array.from(pagination.querySelectorAll(".cm-page"));items.forEach(function(item){item.addEventListener("click",function(){const realIndex=Number(item.dataset.realIndex);normalizeBeforeMove();goToRealIndex(realIndex)})});function goToRealIndex(targetRealIndex){if(isAnimating||targetRealIndex===currentRealIndex)return;normalizeBeforeMove();let targetDomIndex;if(currentRealIndex===0&&targetRealIndex===realCount-1){targetDomIndex=currentDomIndex-1}else if(currentRealIndex===realCount-1&&targetRealIndex===0){targetDomIndex=currentDomIndex+1}else{targetDomIndex=findNearestDomIndex(targetRealIndex)}moveToDomIndex(targetDomIndex,targetRealIndex)}function moveToDomIndex(targetDomIndex,targetRealIndex){isAnimating=true;currentDomIndex=targetDomIndex;currentRealIndex=targetRealIndex;setActive(currentDomIndex,currentRealIndex);const moveX=getCenterMove(currentDomIndex);track.style.transition="transform 0.75s cubic-bezier(0.22, 1, 0.36, 1)";track.style.transform="translateX("+(-moveX)+"px)"}function normalizeBeforeMove(){let needReset=false;let newDomIndex=currentDomIndex;if(currentDomIndex<realCount){newDomIndex=currentDomIndex+realCount;needReset=true}if(currentDomIndex>=realCount*2){newDomIndex=currentDomIndex-realCount;needReset=true}if(!needReset)return;currentDomIndex=newDomIndex;section.classList.add("cm-resetting");setActive(currentDomIndex,currentRealIndex);const moveX=getCenterMove(currentDomIndex);track.style.transition="none";track.style.transform="translateX("+(-moveX)+"px)";track.offsetHeight;section.classList.remove("cm-resetting");track.style.transition="transform 0.75s cubic-bezier(0.22, 1, 0.36, 1)"}function findNearestDomIndex(targetRealIndex){const candidates=items.map(function(item,domIndex){return{domIndex:domIndex,realIndex:Number(item.dataset.realIndex),distance:Math.abs(domIndex-currentDomIndex)}}).filter(function(obj){return obj.realIndex===targetRealIndex}).sort(function(a,b){return a.distance-b.distance});return candidates[0].domIndex}function setActive(domIndex,realIndex){items.forEach(function(item){item.classList.remove("active")});pages.forEach(function(page){page.classList.remove("active")});if(items[domIndex]){items[domIndex].classList.add("active")}if(pages[realIndex]){pages[realIndex].classList.add("active")}items[domIndex].offsetWidth}function getCenterMove(domIndex){const activeItem=items[domIndex];const viewportWidth=viewport.offsetWidth;const itemLeft=activeItem.offsetLeft;const itemWidth=activeItem.offsetWidth;return itemLeft-viewportWidth/2+itemWidth/2}track.addEventListener("transitionend",function(e){if(e.target!==track||e.propertyName!=="transform")return;isAnimating=false});window.addEventListener("resize",function(){section.classList.add("cm-resetting");const moveX=getCenterMove(currentDomIndex);track.style.transition="none";track.style.transform="translateX("+(-moveX)+"px)";track.offsetHeight;section.classList.remove("cm-resetting");track.style.transition="transform 0.75s cubic-bezier(0.22, 1, 0.36, 1)"});setTimeout(function(){setActive(currentDomIndex,currentRealIndex);const moveX=getCenterMove(currentDomIndex);section.classList.add("cm-resetting");track.style.transition="none";track.style.transform="translateX("+(-moveX)+"px)";track.offsetHeight;section.classList.remove("cm-resetting");track.style.transition="transform 0.75s cubic-bezier(0.22, 1, 0.36, 1)"} ,100)});